		return false;
	for (u32 i = 0; i < value->nad_old_entry.count; i++)
		if (!xdrgen_encode_notify_remove4(xdr, &value->nad_old_entry.element[i]))
			return false;
	if (!xdrgen_encode_notify_entry4(xdr, &value->nad_new_entry))
		return false;
